"""
title: LocalCompute Setup Assistent
author: LocalCompute
version: 2.0.0
description: Beheerderstool voor het koppelen van Exact Online, Moneybird, M365, Google en IMAP mailboxen.
requirements: requests
"""

import os
from typing import Any, Dict, Optional
import requests


class Tools:
    def __init__(self):
        self.service_url = os.getenv("MAIL_SERVICE_URL", "http://m365-mail-service:8000")

    def _url(self, path: str) -> str:
        return f"{self.service_url}{path}"

    def check_all_connections(self) -> Dict[str, Any]:
        """
        Controleer de status van alle integraties: mailboxen, Exact Online en Moneybird.

        Gebruik ALTIJD als eerste wanneer de beheerder het setup-scherm opent,
        of wanneer gevraagd wordt naar de status van koppelingen.

        :return: Overzicht van alle actieve en ontbrekende koppelingen.
        """
        status = {}

        # Mailboxen
        try:
            resp = requests.get(self._url("/mailboxes"), timeout=10)
            mailboxes = resp.json().get("mailboxes", [])
            status["mailboxen"] = {
                "gekoppeld": len(mailboxes) > 0,
                "aantal": len(mailboxes),
                "lijst": [f"{m.get('display_name', m.get('email'))} ({m.get('provider', 'm365')})" for m in mailboxes]
            }
        except Exception as e:
            status["mailboxen"] = {"gekoppeld": False, "fout": str(e)}

        # Exact Online
        try:
            resp = requests.get(self._url("/exact/invoices"), params={"max_results": 1}, timeout=10)
            if resp.status_code == 200:
                status["exact_online"] = {"gekoppeld": True, "status": "✅ Actief"}
            elif resp.status_code == 400 and "niet gekoppeld" in resp.text.lower():
                status["exact_online"] = {"gekoppeld": False, "status": "❌ Niet gekoppeld"}
            else:
                status["exact_online"] = {"gekoppeld": False, "status": f"⚠️ Fout: {resp.status_code}"}
        except Exception as e:
            status["exact_online"] = {"gekoppeld": False, "status": f"⚠️ {str(e)}"}

        # Moneybird
        try:
            resp = requests.get(self._url("/moneybird/invoices"), params={"max_results": 1}, timeout=10)
            if resp.status_code == 200:
                status["moneybird"] = {"gekoppeld": True, "status": "✅ Actief"}
            elif resp.status_code == 400 and "niet gekoppeld" in resp.text.lower():
                status["moneybird"] = {"gekoppeld": False, "status": "❌ Niet gekoppeld"}
            else:
                status["moneybird"] = {"gekoppeld": False, "status": f"⚠️ Fout: {resp.status_code}"}
        except Exception as e:
            status["moneybird"] = {"gekoppeld": False, "status": f"⚠️ {str(e)}"}

        return status

    # ── M365 Mailbox ────────────────────────────────────────────────────────────

    def start_m365_mailbox_setup(self, email: Optional[str] = None) -> Dict[str, Any]:
        """
        Start het koppelen van een Microsoft 365 mailbox via Device Code Flow.

        Gebruik wanneer de beheerder een M365 mailbox wil toevoegen.
        Geen wachtwoord nodig — de medewerker logt zelf in via een code.

        :param email: Optioneel e-mailadres van de gebruiker.
        :return: Instructies met user_code en verificatie-URL.
        """
        try:
            resp = requests.post(self._url("/auth/device/start"), json={"email": email}, timeout=20)
            resp.raise_for_status()
            data = resp.json()
            return {
                "stap": "M365 mailbox koppelen",
                "user_code": data.get("user_code"),
                "verificatie_url": data.get("verification_uri"),
                "device_code": data.get("device_code"),
                "instructie": (
                    f"**Stap 1:** Ga naar {data.get('verification_uri')}\n"
                    f"**Stap 2:** Voer code in: `{data.get('user_code')}`\n"
                    f"**Stap 3:** Log in met het Microsoft 365-account.\n\n"
                    f"Zodra je klaar bent, zeg dan \'klaar\' en ik controleer de koppeling."
                ),
                "verloopt_over": f"{data.get('expires_in', 900) // 60} minuten"
            }
        except Exception as e:
            return {"status": "❌ Fout", "bericht": str(e)}

    def confirm_m365_mailbox(self, device_code: str) -> Dict[str, Any]:
        """
        Controleer of de M365 mailbox koppeling is afgerond.

        Gebruik nadat de beheerder aangeeft klaar te zijn met inloggen.

        :param device_code: De device_code van start_m365_mailbox_setup.
        :return: Status van de koppeling.
        """
        try:
            resp = requests.get(self._url("/auth/device/poll"),
                                params={"device_code": device_code}, timeout=20)
            resp.raise_for_status()
            data = resp.json()
            if data.get("status") == "connected":
                mailbox = data.get("mailbox", {})
                return {
                    "status": "✅ Mailbox succesvol gekoppeld!",
                    "email": mailbox.get("email"),
                    "naam": mailbox.get("display_name"),
                    "bericht": f"De mailbox van {mailbox.get('display_name')} is nu actief."
                }
            elif data.get("status") == "pending":
                return {
                    "status": "⏳ Nog bezig",
                    "bericht": "Nog niet ingelogd. Probeer opnieuw na het inloggen."
                }
            else:
                return data
        except Exception as e:
            return {"status": "❌ Fout", "bericht": str(e)}

    def get_azure_admin_consent_url(self, tenant_id: str, client_id: str) -> Dict[str, Any]:
        """
        Genereer de Azure admin consent URL voor Teams en Agenda toegang.

        Gebruik wanneer de beheerder Teams-berichten of agenda wil koppelen.
        Dit is een eenmalige actie door een Azure Global Administrator.

        Wanneer te gebruiken:
        - Beheerder wil Teams-integratie activeren
        - Beheerder wil agenda-toegang voor medewerkers
        - Foutmelding over onvoldoende rechten bij Teams/Calendar

        :param tenant_id: Azure Tenant ID (te vinden in Azure Portal → Azure Active Directory → Properties).
        :param client_id: Azure App Client ID (zelfde als bij M365 mailbox koppeling).
        :return: De URL die de admin moet openen voor eenmalige toestemming.
        """
        url = f"https://login.microsoftonline.com/{tenant_id}/adminconsent?client_id={client_id}"
        return {
            "status": "Actie vereist door Azure Global Administrator",
            "url": url,
            "instructie": (
                f"**Open deze URL als Azure Global Administrator:**\n{url}\n\n"
                "1. Log in met een account dat Global Administrator rechten heeft\n"
                "2. Klik \'Accepteren\' om toestemming te geven voor de hele organisatie\n"
                "3. Je wordt doorgestuurd — de koppeling is daarna actief\n\n"
                "Dit hoeft maar één keer gedaan te worden voor alle medewerkers."
            ),
            "tenant_id": tenant_id,
            "client_id": client_id,
        }

    # ── IMAP/SMTP ───────────────────────────────────────────────────────────────

    def setup_imap_mailbox(
        self,
        email: str,
        password: str,
        imap_server: str,
        imap_port: int = 993,
        display_name: Optional[str] = None,
    ) -> Dict[str, Any]:
        """
        Koppel een mailbox via IMAP (werkt voor Gmail, Outlook, zakelijke mail, etc.).

        Gebruik wanneer de beheerder een mailbox wil koppelen via IMAP/SMTP
        in plaats van via Microsoft 365 of Google OAuth.

        Voor Gmail: gebruik een App Password (niet het gewone wachtwoord).
        Zie: myaccount.google.com/apppasswords

        Veelgebruikte servers:
        - Gmail: imap.gmail.com poort 993
        - Outlook/Hotmail: outlook.office365.com poort 993
        - Yahoo: imap.mail.yahoo.com poort 993

        :param email: E-mailadres van de mailbox.
        :param password: Wachtwoord of App Password.
        :param imap_server: IMAP server adres (bijv. imap.gmail.com).
        :param imap_port: IMAP poort (standaard 993 voor SSL).
        :param display_name: Weergavenaam (optioneel, standaard = email).
        :return: Status van de koppeling.
        """
        try:
            resp = requests.post(self._url("/imap/connect"), json={
                "username": email,
                "password": password,
                "imap_server": imap_server,
                "imap_port": imap_port,
                "display_name": display_name or email,
            }, timeout=20)
            if resp.status_code == 200:
                data = resp.json()
                return {
                    "status": "✅ IMAP mailbox succesvol gekoppeld!",
                    "username": email,
                    "server": imap_server,
                    "bericht": f"{display_name or email} is nu actief via IMAP."
                }
            else:
                detail = resp.json().get("detail", resp.text)
                return {
                    "status": "❌ Koppeling mislukt",
                    "fout": detail,
                    "tip": "Controleer het wachtwoord en serveradres. Voor Gmail: gebruik een App Password."
                }
        except Exception as e:
            return {"status": "❌ Fout", "bericht": str(e)}

    # ── Exact Online ────────────────────────────────────────────────────────────

    def get_exact_setup_url(self, client_id: str, client_secret: str, division: int) -> Dict[str, Any]:
        """
        Start de Exact Online koppeling. Geef de OAuth login URL terug.

        Stap 1 van de Exact koppeling:
        1. Roep deze functie aan met Client ID, Client Secret en divisienummer
        2. De beheerder opent de URL en logt in bij Exact
        3. Na inloggen: callback.localcompute.nl toont de callback URL
        4. Beheerder kopieert die URL en roept complete_exact_setup aan

        Client ID en Secret aanmaken op apps.exactonline.com.
        Divisienummer staat in de URL als je ingelogd bent bij Exact.

        :param client_id: Client ID van de Exact Online app.
        :param client_secret: Client Secret van de Exact Online app.
        :param division: Exact Online divisienummer.
        :return: De OAuth URL om te openen in de browser.
        """
        try:
            resp = requests.post(self._url("/exact/setup/start"), json={
                "client_id": client_id,
                "client_secret": client_secret,
                "division": division,
            }, timeout=20)
            resp.raise_for_status()
            data = resp.json()
            return {
                "stap": "1/2 — Open de URL in uw browser",
                "url": data.get("auth_url"),
                "instructie": (
                    f"**Open deze URL in uw browser:**\n{data.get(\'auth_url\')}\n\n"
                    "Log in met uw Exact Online admin-account en geef toestemming.\n"
                    "Na het inloggen ziet u op callback.localcompute.nl een \'📋 Kopieer URL\' knop.\n"
                    "Kopieer die volledige URL en plak hem hier."
                )
            }
        except Exception as e:
            return {"status": "fout", "bericht": str(e)}

    def complete_exact_setup(
        self,
        client_id: str,
        client_secret: str,
        callback_url: str,
        division: int,
    ) -> Dict[str, Any]:
        """
        Voltooi de Exact Online koppeling met de callback URL.

        Stap 2 van de Exact koppeling — nadat de beheerder de callback URL heeft geplakt.

        :param client_id: Client ID van de Exact Online app.
        :param client_secret: Client Secret van de Exact Online app.
        :param callback_url: Volledige callback URL (van callback.localcompute.nl).
        :param division: Exact Online divisienummer.
        :return: Status van de koppeling.
        """
        try:
            from urllib.parse import urlparse, parse_qs
            parsed = urlparse(callback_url)
            params = parse_qs(parsed.query)
            code = params.get("code", [None])[0]
            if not code:
                code = callback_url.strip()
        except Exception:
            code = callback_url.strip()

        if not code:
            return {
                "status": "fout",
                "bericht": "Geen code gevonden. Plak de volledige URL van callback.localcompute.nl."
            }

        try:
            resp = requests.post(self._url("/exact/connect"), json={
                "client_id": client_id,
                "client_secret": client_secret,
                "authorization_code": code,
                "division": division,
            }, timeout=20)
            if resp.status_code == 200:
                return {
                    "status": "✅ Exact Online succesvol gekoppeld!",
                    "divisie": division,
                    "bericht": "Exact Online is actief. Gebruikers kunnen nu facturen, debiteuren en boekingen opvragen."
                }
            else:
                detail = resp.json().get("detail", resp.text)
                return {"status": "❌ Mislukt", "fout": detail}
        except Exception as e:
            return {"status": "❌ Fout", "bericht": str(e)}

    # ── Moneybird ───────────────────────────────────────────────────────────────

    def setup_moneybird(self, api_token: str) -> Dict[str, Any]:
        """
        Koppel Moneybird via een persoonlijk API token.

        API token aanmaken:
        1. Log in op moneybird.com
        2. Instellingen → Integraties → API
        3. Klik \'Nieuw token aanmaken\'
        4. Kopieer het token en plak het hier

        :param api_token: Het Moneybird API token.
        :return: Status van de koppeling.
        """
        try:
            resp = requests.post(self._url("/moneybird/connect"), json={
                "api_token": api_token,
            }, timeout=20)
            if resp.status_code == 200:
                data = resp.json()
                return {
                    "status": "✅ Moneybird succesvol gekoppeld!",
                    "administratie": data.get("administration"),
                    "bericht": "Moneybird is actief. Gebruikers kunnen nu facturen en offertes opvragen."
                }
            else:
                detail = resp.json().get("detail", resp.text)
                return {"status": "❌ Mislukt", "fout": detail}
        except Exception as e:
            return {"status": "❌ Fout", "bericht": str(e)}

    def setup_google_oauth(self, client_id: str, client_secret: str) -> dict:
        """
        Start Google Workspace koppeling via OAuth.

        Gebruik wanneer de beheerder een Google Workspace of Gmail account wil koppelen.

        Hoe een Google OAuth Client ID aanmaken:
        1. Ga naar console.cloud.google.com
        2. Maak een project aan (of gebruik bestaand project)
        3. Schakel Gmail API en Google Calendar API in via Library
        4. Ga naar Credentials → Create Credentials → OAuth 2.0 Client ID
        5. Kies type: Web application
        6. Voeg redirect URI toe: https://callback.localcompute.nl/google
        7. Kopieer Client ID en Client Secret en plak ze hier

        :param client_id: Google OAuth Client ID.
        :param client_secret: Google OAuth Client Secret.
        :return: Login URL voor de beheerder.
        """
        try:
            resp = requests.post(self._url("/google/oauth/setup"), json={
                "client_id": client_id,
                "client_secret": client_secret,
            }, timeout=20)
            resp.raise_for_status()
            data = resp.json()
            return {
                "stap": "1/2 — Open de URL in uw browser",
                "url": data.get("auth_url"),
                "instructie": (
                    f"**Open deze URL in uw browser:**\n{data.get('auth_url')}\n\n"
                    "Log in met uw Google account en geef toestemming voor Gmail en Agenda.\n"
                    "Na het inloggen ziet u op callback.localcompute.nl/google een knop.\n"
                    "Kopieer de volledige URL en plak hem hier (stap 2)."
                )
            }
        except Exception as e:
            return {"status": "fout", "bericht": str(e)}

    def complete_google_oauth(self, callback_url: str) -> dict:
        """
        Voltooi Google koppeling met de callback URL van callback.localcompute.nl/google.

        Gebruik nadat de beheerder de callback URL heeft geplakt.

        :param callback_url: Volledige URL van callback.localcompute.nl/google na inloggen.
        :return: Status van de koppeling.
        """
        try:
            from urllib.parse import urlparse, parse_qs
            parsed = urlparse(callback_url)
            params = parse_qs(parsed.query)
            code = params.get("code", [None])[0]
            state = params.get("state", [None])[0]
            if not code:
                return {"status": "fout", "bericht": "Geen code gevonden. Plak de volledige URL."}
            resp = requests.post(self._url("/google/oauth/complete"), json={
                "code": code,
                "state": state,
            }, timeout=20)
            if resp.status_code == 200:
                data = resp.json()
                return {
                    "status": "✅ Google account succesvol gekoppeld!",
                    "email": data.get("email"),
                    "naam": data.get("display_name"),
                    "bericht": data.get("message", "Gmail en Agenda zijn nu beschikbaar.")
                }
            else:
                return {"status": "❌ Mislukt", "fout": resp.json().get("detail", resp.text)}
        except Exception as e:
            return {"status": "fout", "bericht": str(e)}

