"""
title: Knowledge Router
author: LocalCompute
version: 3.3.5
description: Keyword-based routing naar de juiste Knowledge collection. Geen HTTP-calls naar OWUI (voorkomt deadlock). Collection IDs worden als valve geconfigureerd.
type: filter
required_open_webui_version: 0.4.0
"""

import re
import requests
from typing import Optional
from pydantic import BaseModel, Field


class Filter:
    class Valves(BaseModel):
        WEBSHOP_COLLECTION_ID: str = Field(
            default="65f4394b-9871-4854-b0ca-ec17b870eb99",
            description="Collection ID van de Webshop knowledge collection"
        )
        PERSONEEL_COLLECTION_ID: str = Field(
            default="c8e64e2e-cff0-4f29-bc5f-d04fe88c7fb7",
            description="Collection ID van de Personeel knowledge collection"
        )
        SEARXNG_URL: str = Field(
            default="http://searxng:8080",
            description="SearXNG URL voor websearch (Docker service naam)"
        )
        WEBSEARCH_RESULTS: int = Field(
            default=5,
            description="Aantal websearch resultaten"
        )
        ENABLED: bool = Field(
            default=True,
            description="Filter aan/uit"
        )
        DEBUG: bool = Field(
            default=False,
            description="Debug logging"
        )
        WEBSHOP_SOURCE_FILE_PATH: str = Field(
            default="/app/backend/data/uploads/6c372d53-adee-42db-8b44-9719b699f1d9_PC_Modellen.txt",
            description="Bronbestand met gestructureerde PC-modellen (fallback)"
        )
        WEBSHOP_CONTEXT_MAX_LINES: int = Field(
            default=20,
            description="Max aantal modelregels in fallback context"
        )
        PERSONEEL_FALLBACK_ENABLED: bool = Field(
            default=True,
            description="Voeg gevalideerde HR-fallback context toe"
        )

    def __init__(self):
        self.valves = self.Valves()

    def _log(self, msg: str):
        if self.valves.DEBUG:
            print(f"[KnowledgeRouter] {msg}")

    def classify(self, question: str) -> str:
        """Keyword-based routing. Snel en betrouwbaar."""
        q = question.lower()

        # Personeel keywords
        personeel = [
            "verlof", "vakantie", "ziek", "ziekte", "salaris", "loon",
            "contract", "ontslag", "opzegtermijn", "cao", "arbeid", "werknemer",
            "werktijd", "dienst", "betaald", "vergoeding", "pensioen",
            "zwanger", "ouderschap", "feestdag", "vrij", "afwezig"
        ]

        # Webshop keywords
        webshop = [
            "pc", "computer", "gaming", "rtx", "gpu", "cpu", "intel", "amd",
            "supernova", "andromeda", "nighthawk", "nova", "prism", "hyperion",
            "prijs", "kosten", "euro", "kopen", "bestellen", "voorraad",
            "headset", "toetsenbord", "muis", "monitor", "laptop", "accessoire",
            "upgrade", "configuratie", "noanoella", "hatsune", "strix", "tuf",
            "5090", "5080", "5070", "5060", "4090", "4080", "4070"
        ]

        # Websearch keywords (duidelijk extern)
        websearch = [
            "nieuws", "verkiezing", "weer", "politiek", "sport", "wikipedia"
        ]

        p_score = sum(1 for k in personeel if k in q)
        w_score = sum(1 for k in webshop if k in q)
        ws_score = sum(1 for k in websearch if k in q)

        self._log(f"Scores — Personeel: {p_score}, Webshop: {w_score}, Websearch: {ws_score}")

        if ws_score > 0 and ws_score > w_score and ws_score > p_score:
            return "websearch"
        if p_score > 0 and p_score >= w_score:
            return "personeel"
        if w_score > 0:
            return "webshop"
        if p_score > 0:
            return "personeel"

        return "none"

    def do_websearch(self, query: str) -> Optional[str]:
        """SearXNG websearch — geen OWUI-deadlock risico."""
        try:
            r = requests.get(
                f"{self.valves.SEARXNG_URL}/search",
                params={"q": query, "format": "json", "language": "nl"},
                timeout=10
            )
            if r.status_code == 200:
                results = r.json().get("results", [])[:self.valves.WEBSEARCH_RESULTS]
                if not results:
                    return None
                parts = []
                for i, res in enumerate(results, 1):
                    parts.append(
                        f"[Bron {i}] {res.get('title','')}\n{res.get('content','')}\nURL: {res.get('url','')}"
                    )
                return "\n\n".join(parts)
        except Exception as e:
            self._log(f"Websearch mislukt: {e}")
        return None

    def _build_webshop_context(self, query: str) -> str:
        """Bouw compacte, schone productcontext uit gestructureerd bronbestand."""
        try:
            with open(self.valves.WEBSHOP_SOURCE_FILE_PATH, "r", encoding="utf-8", errors="ignore") as f:
                rows = [ln.strip() for ln in f if ln.strip().startswith("Model:")]

            if not rows:
                return ""

            q = query.lower()
            tokens = [t for t in re.findall(r"[a-z0-9]+", q) if len(t) > 2]

            def score(row: str) -> int:
                r = row.lower()
                s = 0
                for t in tokens:
                    if t in r:
                        s += 2
                if "rtx 5080" in q and "rtx 5080" in r:
                    s += 6
                if "supernova" in q and "supernova" in r:
                    s += 6
                if "prijs" in q and "actieprijs" in r:
                    s += 2
                return s

            ranked = sorted(rows, key=score, reverse=True)
            selected = [r for r in ranked if score(r) > 0][: self.valves.WEBSHOP_CONTEXT_MAX_LINES]

            # Guardrail: bij expliciete RTX 5080-vraag alleen exacte RTX 5080-regels
            if "rtx 5080" in q:
                selected_5080 = [r for r in selected if "rtx 5080" in r.lower()]
                if selected_5080:
                    selected = selected_5080

            if not selected:
                selected = ranked[: min(30, self.valves.WEBSHOP_CONTEXT_MAX_LINES)]

            cleaned = [
                r.replace("Actieprijs: EUR", "Prijs: EUR").replace("  ", " ")
                for r in selected
            ]
            self._log(f"Fallback context regels: {len(cleaned)}")
            return "\n".join(cleaned)
        except Exception as e:
            self._log(f"Fallback context bouwen mislukt: {e}")
            return ""

    def _set_route_system_prompt(self, messages: list, route_key: str, prompt: str) -> list:
        marker = f"[KR_ROUTE={route_key}]"
        full_prompt = marker + "\n" + prompt
        if messages and messages[0].get("role") == "system":
            content = messages[0].get("content", "")
            if isinstance(content, str) and content.startswith("[KR_ROUTE="):
                messages[0]["content"] = full_prompt
                return messages
        return [{"role": "system", "content": full_prompt}] + messages

    def _build_personeel_context(self, query: str) -> str:
        q = query.lower()
        lines = []
        if any(k in q for k in ["vakantie", "verlof", "cao", "vakantieuren"]):
            lines.append("CAO ETD art. 5.2: fulltime werknemer heeft recht op 190 uur vakantie per jaar.")
            lines.append("Personeelshandboek Redux sectie 8.1: 190 uur vakantie per jaar.")
            lines.append("Extra dag (7,6 uur) bij geen ziekte in kalenderjaar.")
            lines.append("Leeftijdsopbouw extra dagen: 50-54 jaar +1 dag, 55-59 jaar +2 dagen, 60+ +3 dagen.")
        return "\n".join(lines)

    def inlet(self, body: dict, __user__: Optional[dict] = None) -> dict:
        if not self.valves.ENABLED:
            return body

        # Haal het laatste gebruikersbericht op
        messages = body.get("messages", [])
        last_user_msg = None
        for msg in reversed(messages):
            if msg.get("role") == "user":
                content = msg.get("content", "")
                if isinstance(content, str):
                    last_user_msg = content
                elif isinstance(content, list):
                    last_user_msg = " ".join(
                        p.get("text", "") for p in content
                        if isinstance(p, dict) and p.get("type") == "text"
                    )
                break

        if not last_user_msg:
            return body

        route = self.classify(last_user_msg)
        self._log(f"Route: {route} voor '{last_user_msg[:60]}'")

        if route == "websearch":
            context = self.do_websearch(last_user_msg)
            if context:
                search_prompt = (
                    f"Gebruik de volgende zoekresultaten om de vraag te beantwoorden. "
                    f"Antwoord in het Nederlands.\n\n{context}"
                )
                body["messages"] = self._set_route_system_prompt(messages, "websearch", search_prompt)
            return body

        elif route == "webshop" and self.valves.WEBSHOP_COLLECTION_ID:
            col_id = self.valves.WEBSHOP_COLLECTION_ID
            existing_files = body.get("files", []) or []
            non_collection_files = [
                f for f in existing_files
                if not (isinstance(f, dict) and f.get("type") == "collection")
            ]
            body["files"] = non_collection_files + [{"type": "collection", "id": col_id}]
            self._log(f"Webshop collection geforceerd: {col_id}")

            # Grounding prompt
            grounding = (
                "Je bent een assistent van Redux Gaming. "
                "Gebruik UITSLUITEND informatie uit de aangeleverde kennisbank voor productinformatie. "
                "Verzin GEEN modelnamen, prijzen of specs. "
                "Antwoord ALTIJD in het Nederlands."
            )
            # Fallback (production): compacte context uit gestructureerde modellenlijst
            fallback_context = self._build_webshop_context(last_user_msg)
            if fallback_context:
                grounding = (
                    grounding
                    + "\n\nGebruik daarnaast deze gestructureerde modellenlijst als bron:\n"
                    + fallback_context
                )

            body["messages"] = self._set_route_system_prompt(messages, "webshop", grounding)

        elif route == "personeel" and self.valves.PERSONEEL_COLLECTION_ID:
            col_id = self.valves.PERSONEEL_COLLECTION_ID
            existing_files = body.get("files", []) or []
            non_collection_files = [
                f for f in existing_files
                if not (isinstance(f, dict) and f.get("type") == "collection")
            ]
            body["files"] = non_collection_files + [{"type": "collection", "id": col_id}]
            self._log(f"Personeel collection geforceerd: {col_id}")
            personeel_prompt = (
                "Je bent een HR-assistent van Redux Gaming. "
                "Gebruik UITSLUITEND informatie uit de aangeleverde CAO/handboek-context. "
                "Als informatie ontbreekt, zeg dat expliciet. "
                "Antwoord ALTIJD in het Nederlands."
            )
            if self.valves.PERSONEEL_FALLBACK_ENABLED:
                pctx = self._build_personeel_context(last_user_msg)
                if pctx:
                    personeel_prompt += "\n\nGebruik daarnaast deze gevalideerde HR-feiten:\n" + pctx
            body["messages"] = self._set_route_system_prompt(messages, "personeel", personeel_prompt)

        return body

    def outlet(self, body: dict, __user__: Optional[dict] = None) -> dict:
        return body

"""
title: Redux RAG Grounding Filter
description: Injecteert KB-context via directe Qdrant+Ollama. Slaat mail-gerelateerde vragen over.
author: Redux Gaming
version: 4.1
required_open_webui_version: 0.3.0
"""

import json
import urllib.request
from pydantic import BaseModel, Field
from typing import Optional


OLLAMA_URL = "http://ollama:11434"
QDRANT_URL = "http://qdrant:6333"
EMBED_MODEL = "bge-m3:latest"
COLLECTION = "open-webui_knowledge"

# Trefwoorden die mail/OAuth-flow betreffen — geen RAG nodig
MAIL_KEYWORDS = [
    "mail", "mailbox", "e-mail", "email", "microsoft 365", "m365",
    "outlook", "koppel", "koppelen", "inbox", "berichten", "device code",
    "inloggen microsoft", "microsoft account",
]


def _is_mail_query(text: str) -> bool:
    t = text.lower()
    return any(kw in t for kw in MAIL_KEYWORDS)


def _embed(text: str) -> list:
    body = json.dumps({"model": EMBED_MODEL, "prompt": text}).encode()
    req = urllib.request.Request(
        f"{OLLAMA_URL}/api/embeddings",
        data=body,
        headers={"Content-Type": "application/json"},
        method="POST"
    )
    with urllib.request.urlopen(req, timeout=20) as resp:
        data = json.loads(resp.read())
    return data["embedding"]


def _search_qdrant(embedding: list, k: int = 5, score_threshold: float = 0.3) -> list:
    body = json.dumps({
        "vector": embedding,
        "limit": k,
        "score_threshold": score_threshold,
        "with_payload": True,
        "with_vector": False
    }).encode()
    req = urllib.request.Request(
        f"{QDRANT_URL}/collections/{COLLECTION}/points/search",
        data=body,
        headers={"Content-Type": "application/json"},
        method="POST"
    )
    with urllib.request.urlopen(req, timeout=10) as resp:
        data = json.loads(resp.read())
    return data.get("result", [])


class Filter:
    class Valves(BaseModel):
        max_results: int = Field(default=5, description="Max KB resultaten")
        min_score: float = Field(default=0.3, description="Min relevantiescore")
        inject_think: bool = Field(default=False, description="Voeg /think toe aan user msg")

    def __init__(self):
        self.valves = self.Valves()

    def _get_kb_context(self, query: str) -> str:
        try:
            embedding = _embed(query)
            results = _search_qdrant(embedding, k=self.valves.max_results, score_threshold=self.valves.min_score)
            if not results:
                return ""
            parts = []
            for hit in results:
                text = hit.get("payload", {}).get("text", "")
                score = hit.get("score", 0)
                if text:
                    parts.append(f"[Score: {score:.2f}]\n{text}")
            return "\n\n---\n\n".join(parts)
        except Exception as e:
            print(f"[Redux Filter v4.1] Fout: {e}")
            return ""

    def inlet(self, body: dict, __user__: Optional[dict] = None) -> dict:
        messages = body.get("messages", [])
        if not messages:
            return body

        last_user_msg = ""
        last_user_idx = -1
        for i in range(len(messages) - 1, -1, -1):
            msg = messages[i]
            if msg.get("role") == "user":
                content = msg.get("content", "")
                if isinstance(content, list):
                    for item in content:
                        if isinstance(item, dict) and item.get("type") == "text":
                            last_user_msg = item.get("text", "")
                            break
                else:
                    last_user_msg = str(content)
                last_user_idx = i
                break

        if not last_user_msg.strip():
            return body

        # Mail-vragen overslaan — model gebruikt tool, geen RAG nodig
        if _is_mail_query(last_user_msg):
            return body

        kb_context = self._get_kb_context(last_user_msg)

        if kb_context:
            context_system = {
                "role": "system",
                "content": (
                    "## Redux Gaming Kennisbank — Gevonden informatie:\n\n"
                    + kb_context
                    + "\n\n---\n"
                    "INSTRUCTIE: Gebruik bovenstaande informatie voor Redux Gaming "
                    "product/prijs/HR vragen. Citeer prijzen letterlijk. Verzin NIETS."
                )
            }
            body["messages"].insert(last_user_idx, context_system)
            last_user_idx += 1

        if self.valves.inject_think:
            msg = body["messages"][last_user_idx]
            if msg.get("role") == "user":
                original = msg.get("content", "")
                if isinstance(original, str) and not original.startswith("/think"):
                    msg["content"] = "/think\n" + original

        return body

    def outlet(self, body: dict, __user__: Optional[dict] = None) -> dict:
        return body

