]
INTENT_DEBITEUREN = [
    "debiteur", "debiteuren", "debiteurenoverzicht", "wie moet ik nog ontvangen",
    "openstaand bedrag", "klanten openstaand", "receivable",
]
INTENT_TRANSACTIES = [
    "transactie", "transacties", "boeking", "boekingen", "laatste boekingen",
    "recente transacties", "wat is er geboekt", "transaction",
]


def _http_get(path: str, params: dict = None) -> dict:
    url = f"{EXACT_SERVICE_URL}{path}"
    if params:
        query = "&".join(f"{k}={v}" for k, v in params.items())
        url = f"{url}?{query}"
    req = urllib.request.Request(url, headers={"Content-Type": "application/json"}, method="GET")
    try:
        with urllib.request.urlopen(req, timeout=15) as resp:
            return json.loads(resp.read())
    except urllib.error.HTTPError as e:
        return {"error": f"HTTP {e.code}: {e.read().decode()[:200]}"}
    except Exception as e:
        return {"error": str(e)}


def _detect_intent(text: str) -> Optional[str]:
    t = text.lower()
    if any(kw in t for kw in INTENT_DEBITEUREN):
        return "debiteuren"
    if any(kw in t for kw in INTENT_FACTUREN):
        return "facturen"
    if any(kw in t for kw in INTENT_TRANSACTIES):
        return "transacties"
    return None


def _format_invoices(data: dict) -> str:
    invoices = data.get("invoices", data.get("results", []))
    if not invoices:
        return "Exact Online: geen openstaande facturen gevonden."
    lines = [f"Exact Online — {len(invoices)} openstaande facturen:"]
    for inv in invoices:
        nr = inv.get("nummer", "?")
        klant = inv.get("klant", "?")
        bedrag = inv.get("bedrag", "?")
        datum = inv.get("datum", "")
        omschrijving = inv.get("omschrijving", "")
        lines.append(f"- Factuur {nr} | {omschrijving} | EUR {bedrag} | {datum} | klant {klant}")
    return "\n".join(lines)


def _format_receivables(data: dict) -> str:
    items = data.get("receivables", data.get("results", []))
    if not items:
        return "Exact Online: geen openstaande debiteuren gevonden."
    lines = [f"Exact Online — {len(items)} openstaande debiteuren:"]
    for r in items:
        klant = r.get("klant", r.get("naam", "?"))
        bedrag = r.get("bedrag", r.get("openstaand", "?"))
        datum = r.get("vervaldatum", r.get("datum", ""))
        lines.append(f"- {klant} | EUR {bedrag} | vervaldatum {datum}")
    return "\n".join(lines)


def _format_transactions(data: dict) -> str:
    items = data.get("transactions", data.get("results", []))
    if not items:
        return "Exact Online: geen recente transacties gevonden."
    lines = [f"Exact Online — {len(items)} recente transacties:"]
    for t in items:
        datum = t.get("datum", t.get("date", ""))
        omschrijving = t.get("omschrijving", t.get("description", ""))
        bedrag = t.get("bedrag", t.get("amount", "?"))
        rekening = t.get("rekening", t.get("account", ""))
        lines.append(f"- {datum} | {omschrijving} | EUR {bedrag} | {rekening}")
    return "\n".join(lines)


class Filter:
    def inlet(self, body: dict, __user__: Optional[dict] = None) -> dict:
        messages = body.get("messages", [])
        if not messages:
            return body

        last_user_msg = next(
            (m["content"] for m in reversed(messages) if m.get("role") == "user"),
            ""
        )
        if not isinstance(last_user_msg, str):
            return body

        intent = _detect_intent(last_user_msg)
        if not intent:
            return body

        # Haal data op
        if intent == "facturen":
            data = _http_get("/exact/invoices", {"max_results": 15})
            if "error" in data:
                context = f"Exact Online fout: {data['error']}"
            else:
                context = _format_invoices(data)

        elif intent == "debiteuren":
            data = _http_get("/exact/receivables", {"max_results": 15})
            if "error" in data:
                context = f"Exact Online fout: {data['error']}"
            else:
                context = _format_receivables(data)

        elif intent == "transacties":
            data = _http_get("/exact/transactions", {"max_results": 15})
            if "error" in data:
                context = f"Exact Online fout: {data['error']}"
            else:
                context = _format_transactions(data)

        else:
            return body

        # Injecteer als context in het user bericht
        injected = f"[EXACT ONLINE DATA]\n{context}\n[/EXACT ONLINE DATA]\n\n{last_user_msg}"

        # Update het laatste user bericht
        for i in range(len(messages) - 1, -1, -1):
            if messages[i].get("role") == "user":
                messages[i]["content"] = injected
                break

        body["messages"] = messages
        return body

    def outlet(self, body: dict, __user__: Optional[dict] = None) -> dict:
        return body
